module top_module(
    input [3:0] a,
    input [3:0] b,
    input [1:0] opcode,
    output [3:0] result
);reg [3:0] unused_temp;

always @(*) begin
    case(opcode)
        2'b00: unused_temp = a + b;
        2'b01: unused_temp = a - b;
        2'b10: unused_temp = a & b;
        2'b11: unused_temp = a | b;
    endcase
end

assign result = unused_temp;

endmodule
